function rooms(st,en)
{ 
    var tst = '';
    for(ri=st; ri<=en; ri++) tst += '<td width=20% bgcolor=#'+r_color[ri]+'><div align=center><font class=freetxt><b><font color=#1959AF><font color=#222222>'+r_names[ri]+' </b>[ '+crcount[ri]+' ]<b></font><img src=http://image.neverlands.ru/1x1.gif width=1 height=20 align=absmiddle><br><input type=button value="Перейти" '+(r_avail[ri] == 1 ? 'onclick="location=\'main.php?get_id=2&go=47&rid='+ri+'&vcode='+vcode[3]+'\'" class=fr_but' : (!r_avail[ri] ? 'class=fr_but DISABLED' : 'class=fr_but_dis DISABLED'))+'> <a href="javascript:top.seeroom(\'arena'+(ri+sr)+'\')"><img src=http://image.neverlands.ru/help/6.gif width=15 height=15 border=0 title="Просмотр комнаты" align=absmiddle></a><br>'+r_level[ri]+'</td>';
    return tst;
