function updateDwarfshop(response)
{
    clearTimers();
    if (objStatus['timeLeft'] > 0) {
        showTimeLeft(objStatus['timeLeft']);
    } else {
        showRecipes(response);
    }
}

function showTimeLeft(timeLeft)
{
    var t = '<div><fieldset><legend align="center"><b>Идёт работа</b></legend><div style="margin: 0 auto; width: 740px; text-align: center;"><br />';
    if (timeLeft > 0) {
        t += 'До окончания крафта осталось <b id="timer_craft"></b><br />';
        addTimer('craft', timeLeft + 1, function () {
            getStatus();
        }, true);
        if (objActions['accelerate']) {
            t += '<br /><input type="button" class="lbut" value="Завершить за 0.5 DNV" onclick="if (confirm(\'Уверены, что хотите завершить крафт за 0.5 DNV\')) accelerateCraft();" /><br />';
        }
    } else {
        t += 'Крафт завершен<br />';
    }
    t += '</div></fieldset></div>';
    document.getElementById('Dynamic').innerHTML = t;
}

function showRecipes(response)
{
    var i, x, recipe, item, res, weapon, userCount, c;
    var t = '<div>';

    t += '<div style="text-align: center"><div style="margin: 0 auto">';
    for(i in categories) {
        if (categories.hasOwnProperty(i)) {
            t += '<img src="http://image.neverlands.ru/gameplay/dwarfshop/categories/cat' + categories[i]['id'] + '.gif" onclick="getRecipes(' + categories[i]['id'] + '); return false;" title="' + categories[i]['name'] + '" style="cursor: pointer;" />';
        }
    }
    t += '</div></div><br />';

    if (response && response['recipes']) {
        t += '<fieldset><legend align="center"><b>Доступные рецепты</b></legend><div style="margin: 0 auto; width: 740px;"><br /><table cellpadding=0 cellspacing=10 border=0 width=100%><tr><td bgcolor=#cccccc><table cellpadding=5 cellspacing=1 border=0 width=100%>';
        t += '<tr> <td bgcolor=#FCFAF3 class=travma align=center><B>Название</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Время</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Исходные ресурсы</B></td> <td bgcolor=#FCFAF3 class=travma align=center><B>Готовая продукция</B></td><td bgcolor=#FCFAF3 class=travma align=center></td></tr>';
        for (var r in response['recipes']) {
            if (response['recipes'].hasOwnProperty(r)) {
                recipe = response['recipes'][r];
                i++;
                c = (i % 2 == 0 ? '#FFFFFF' : '#FCFAF3');

                t += '<tr><td bgcolor=' + c + ' class=nickname align=center>' + recipe['name'] + '</td>' +
                    '<td bgcolor=' + c + ' class=travma align=center><b>' + showTime(recipe['craftTime']) + '</b></td>' +
                    '<td bgcolor=' + c + ' align=center>' +
                    '<table><tr>';
                for (x in recipe['required']) {
                    if (recipe['required'].hasOwnProperty(x)) {
                        t += '<td align="center" class="weaponch">';
                        item = recipe['required'][x];
                        if (item['itemType'] == 1) {
                            if (item['itemId'] == 1) {
                                t += item['count'] + ' NV';
                            } else if (item['itemId'] == 2) {
                                t += item['count'] + ' $';
                            } else if (item['itemId'] == 3) {
                                t += item['count'] + ' DNV';
                            }
                        } else if (item['itemType'] == 2) {
                            res = response['resources'][item['itemId']];
                            t += '<img src="http://image.neverlands.ru/resources/' + item['itemId'] + '.gif" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                            userCount = response['playerResources'][item['itemId']] ? response['playerResources'][item['itemId']] : 0;
                            t += userCount + ' / ' + item['count'];
                        } else if (item['itemType'] == 3) {
                            res = response['weapons'][item['itemId']];
                            t += '<img src="http://image.neverlands.ru/weapon/' + res['image'] + '" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                            userCount = response['playerWeapons'][item['itemId']] ? response['playerWeapons'][item['itemId']] : 0;
                            t += userCount + ' / ' + item['count'];
                        }
                        t += '</td>';
                    }
                }
                t += '</tr></table></td><td bgcolor=' + c + ' align=center><table><tr>';
                for (x in recipe['result']) {
                    if (recipe['result'].hasOwnProperty(x)) {
                        t += '<td align="center" class="weaponch">';
                        item = recipe['result'][x];
                        if (item['itemType'] == 1) {
                            if (item['itemId'] == 1) {
                                t += item['count'] + ' NV';
                            } else if (item['itemId'] == 2) {
                                t += item['count'] + ' $';
                            } else if (item['itemId'] == 3) {
                                t += item['count'] + ' DNV';
                            }
                        } else if (item['itemType'] == 2) {
                            res = response['resources'][item['itemId']];
                            t += '<img src="http://image.neverlands.ru/resources/' + item['itemId'] + '.gif" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                            t += 'x' + item['count'];
                        } else if (item['itemType'] == 3) {
                            res = response['weapons'][item['itemId']];
                            t += '<img src="http://image.neverlands.ru/weapon/' + res['image'] + '" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                            t += 'x' + item['count'];
                        }
                        if (item['probability'] && item['probability'] != '') {
                            t += ' (' + item['probability'] + '%)';
                        }
                        t += '</td>';
                    }
                }
                t += '</tr></table></td><td bgcolor=' + c + ' align=center>';
                if (recipe['canCraft']) {
                    var ibcID = window.external.DwarfCraftGetId();

                    if (ibcID === recipe['id']) {
                        startCraft(ibcID);
                        return;
                    }

                    t += '<input type="button" name="startCraft" onclick="startCraft(' + recipe['id'] + ')" value="Сделать" class=invbut />';
                } else {
                    t += '<input type="button" value="Сделать" class=lbutdis />';
                }
                t += '</td></tr>';
            }
        }
        t += '</table></td></tr></table></div></fieldset>';
    } else {
        var ibcCategory = window.external.DwarfCraftGetCategory();

        if (ibcCategory) {
            getRecipes(ibcCategory);
            return;
        }
    }
    t += '</div>';
    document.getElementById('Dynamic').innerHTML = t;
}

function getStatus()
{
    AjaxGet(scriptName + '?type=dwarfshop&action=getStatus&vcode='+objActions['getStatus']+'&r='+Math.random()+'', function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        updateDwarfshop(response['r']);
    });
}

function getRecipes(category)
{
    window.external.DwarfCraftSetCategory(category);
    AjaxGet(scriptName + '?type=dwarfshop&action=getRecipes&categoryId='+category+'&vcode='+objActions['getRecipes']+'&r='+Math.random()+'', function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        updateDwarfshop(response['r']);
    });
}

function startCraft(recipeId)
{
    window.external.DwarfCraftSetId(recipeId);
    var data = {type: 'dwarfshop', action: 'craft', recipeId: recipeId, vcode: objActions['craft_'+recipeId]};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        window.scrollTo(0, 0);
        updateData(response);
        updateDwarfshop(response['r']);
    });
}

function accelerateCraft()
{
    var data = {type: 'dwarfshop', action: 'accelerate', vcode: objActions['accelerate']};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        updateDwarfshop(response['r']);
    });
}

