function checkNumbers(totalNumbers, pickNumbers)
{
    var i, checked = 0;
    for(i = 1; i <= totalNumbers; i++) {
        if (getById('num_'+i).checked) {
            checked++;
        }
    }

    var disabled = (checked >= pickNumbers);
    for(i = 1; i <= totalNumbers; i++) {
        if (!getById('num_'+i).checked) {
            getById('num_'+i).disabled = disabled;
        }
    }

    getById('ticketButton').disabled = (checked !== pickNumbers);
}

function getStatus()
{
    AjaxGet(scriptName + '?type=lottery&action=getStatus&vcode='+objActions['getStatus']+'&r='+Math.random()+'', function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
    });
}

function buyTicket(totalNumbers)
{
    var numbers = [];
    for(var i = 1; i <= totalNumbers; i++) {
        if (getById('num_'+i).checked) {
            numbers.push(i);
        }
    }

    var data = {type: 'lottery', action: 'buyTicket', numbers: numbers.join(','), vcode: objActions['buyTicket']};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        window.scrollTo(0, 0);
        updateData(response);
        viewBuyTicket();
    });
}

