function showDraws(response)
{
    var i, x, draw;
    var t = '<div>';

    if (response && response['draws']) {
        t += '<fieldset><legend align="center"><b>Прошлые тиражи</b></legend><div style="margin: 0 auto; width: 740px;"><br /><table cellpadding=0 cellspacing=10 border=0 width=100%><tr><td bgcolor=#cccccc><table cellpadding=5 cellspacing=1 border=0 width=100%>';
        t += '<tr> <td bgcolor=#FCFAF3 class=travma align=center><B>Номер</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Время розыгрыша</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Выигрышные номера</B></td> <td bgcolor=#FCFAF3 class=travma align=center><B>Билеты</B></td><td bgcolor=#FCFAF3 class=travma align=center></td></tr>';
        for(var r in response['draws']) {
            if (response['draws'].hasOwnProperty(r)) {
