                t += '<tr><td bgcolor=' + c + ' class=nickname align=center>' + draw['drawId'] + '</td>' +
                    '<td bgcolor=' + c + ' class=travma align=center><b>' + draw['resultTime'] + '</b></td>' +
                    '<td bgcolor=' + c + ' class=travma align=center><b>' + draw['result'] + '</b></td>' +
                    '<td bgcolor=' + c + ' class=travma align=center>Куплено: <b>' + draw['playerTickets'] + '</b><br />Выигрышных: <b>' + draw['activeTickets'] + '</b></td>' +
                    '<td bgcolor=' + c + ' align=center>';

                if (objActions['draw_' + draw['drawId']]) {
                    t += '<input type="button" value="Подробнее" onclick="getDraw(' + draw['drawId'] + ')" class=invbut />';
                } else {
