function getDraw(drawId)
{
    AjaxGet(scriptName + '?type=lottery&action=getDraw&draw='+drawId+'&vcode='+objActions['draw_' + drawId]+'&r='+Math.random()+'', function(xdata) {
        var response = JSON.parse(xdata);
