        //        t += i + ' из ' + response['totalNumbers'] + ': <b>' + response['prizesCount']['n'+i]['count'] + '</b><br />';
        //    }
        //}
        //t += '4 из 15: <b>'+response['secondPrizeCount']+'</b><br />';

        t += 'Ваши билеты: <br />';
        t += '<table cellpadding=0 cellspacing=10 border=0 width=100%><tr><td bgcolor=#cccccc><table cellpadding=5 cellspacing=1 border=0 width=100%>';
