                i++;
                c = (i % 2 === 0 ? '#FFFFFF' : '#FCFAF3');

                t += '<tr><td bgcolor=' + c + ' class=nickname align=center><img src="http://image.neverlands.ru/weapon/qw452.gif" /></td>' +
