                    '<td bgcolor=' + c + ' class=travma>Выбрано: <b>' + ticket['numbers'] + '</b><br />Угадано: <b>'+ticket['validNumbers']+' из '+response['pickNumbers']+'</b><br />Выигрыш: <b>' + ticket['prize'] + ' NV' + (ticket['items'] > 0 ? ' + Bonus' : '') + '</b></td>' +
                    '<td bgcolor=' + c + ' class=travma align=center> ';

                if (ticket['prize'] > 0 || ticket['items'] > 0) {
                    if (objActions['receive_' + ticket['uid']]) {
                        t += '<input type="button" value="Забрать выигрыш" onclick="receivePrize(' + response['drawId'] + ', ' + ticket['uid'] + ')" class=invbut />';
                    } else {
                        t += 'Получено';
                    }
                } else {
                    t += '&nbsp;';
                }

                t += '</td></tr>';
            }
        }
        t += '</table></td></tr></table></div></fieldset>';
    }
    t += '</div>';
    document.getElementById('Dynamic').innerHTML = t;
}

function receivePrize(draw, ticketId)
{
    var data = {type: 'lottery', action: 'receivePrize', draw: draw, ticketId: ticketId, vcode: objActions['receive_' + ticketId]};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        showDraw(response['r']);
    });
}

function GenerateSet() {
    var numbers = JSON.parse(window.external.getLotteryRandom(CHECK_NUMBERS, NUMBERS_COUNT));

    for (var i = 1; i <= NUMBERS_COUNT; i++) {
        getById('num_' + i).checked = false;
        getById('num_' + i).disabled = false;
    }

    for (var i = 0; i < numbers.length; i++) {
        getById('num_' + numbers[i]).checked = true;
    }

    getById('ticketButton').disabled = false;

    return numbers;
}

function BuyAmount() {
    var amount = parseInt(getById('amountToBuy').value);
    var set = null;
    var SETS = [];

    if (isNaN(amount)) {
        alert('Введите корректное число билетов для покупки.');
        return;
    }

    if (amount < 1) amount = 1;
    if (amount > 100) amount = 100;

    var buyInterval = setInterval(function () {
        if (SETS.length < amount) {

            while (!set || SETS.indexOf(set.toString()) !== -1) {
                set = GenerateSet();
                set.sort(function (a, b) { return a - b; });
            }

            SETS.push(set.toString());
            set = null;

            buyTicket(objStatus['totalNumbers']);
        } else {
            clearInterval(buyInterval);
        }
    }, 900);
}

document.onmousedown = t_nick;

function t_nick ()
{
  top.is_ctrl = window.event.ctrlKey;
  top.is_alt = window.event.altKey;
}

function ch_clear_ignor (nick)
{
  while (nick.indexOf ('=') >= 0) nick = nick.replace ('=', '%3D');
  while (nick.indexOf ('+') >= 0) nick = nick.replace ('+', '%2B');
  while (nick.indexOf ('#') >= 0) nick = nick.replace ('#', '%23');
  while (nick.indexOf (' ') >= 0) nick = nick.replace (' ', '%20');
  top.frames['ch_refr'].location='./ch.php?a=ign&s=0&u='+nick;
}

function reverse_alpha_sort (el1,el2) {
    if (el1 > el2) {
        return -1;
    } else if (el1 < el2) {
        return 1;
    } else {
        return 0;
    }
}

function qsort_str(arr,first,last) {
 if (first<last) {
  point=arr[first].split(":")[0];
  i=first;
  j=last;
  while (i<j) {
   while ((arr[i].split(":")[0]<=point) && (i<last)) i++;
   while ((arr[j].split(":")[0]>=point) && (j>first)) j--;
   if (i<j) {
    temp=arr[i];
    arr[i]=arr[j];
    arr[j]=temp;
   }
  }
  temp=arr[first];
  arr[first]=arr[j];
  arr[j]=temp;
  qsort_str(arr,first,j-1);
  qsort_str(arr,j+1,last);
 }
}

function qsort_int(arr,first,last,h) {
 if (first<last) {
  point=parseInt(arr[first].split(":")[2]);
  i=first;
  j=last;
  while (i<j) {
   while ((h*parseInt(arr[i].split(":")[2])<=h*point) && (i<last)) i++;
   while ((h*parseInt(arr[j].split(":")[2])>=h*point) && (j>first)) j--;
   if (i<j) {
    temp=arr[i];
    arr[i]=arr[j];
    arr[j]=temp;
   }
  }
  temp=arr[first];
  arr[first]=arr[j];
  arr[j]=temp;
  qsort_int(arr,first,j-1,h);
  qsort_int(arr,j+1,last,h);
 }
}

function chatlist_build (sort_type)
{
  if (sort_type=='a_z') ChatListU.sort ();
  else if (sort_type=='z_a') ChatListU.sort (reverse_alpha_sort);
  else {

   if (sort_type=='0_33') {
    qsort_int(ChatListU,0,ChatListU.length-1,1);
   }
   else if (sort_type=='33_0') {
    qsort_int(ChatListU,0,ChatListU.length-1,-1);
   }

