var curHP, maxHP, intHP, curMA, maxMA, intMA, interv;

function ins_HP(curh, maxh, curm, maxm, hp_int, ma_int)
{
    intHP = hp_int;
    intMA = ma_int;
    interv = setInterval("cha_HP()",1000);
    if(curm < 0) curm = 0;
    if(maxm <= 0) maxm = 7;
    curHP = curh;
    curMA = curm;
    maxHP = maxh;
    maxMA = maxm;
    cha_HP();
}

function cha_HP()
{
    if(curHP > maxHP) curHP = maxHP;
    if(curMA > maxMA) curMA = maxMA;
    if(curHP >= maxHP && curMA >= maxMA) clearInterval(interv);
    s_hp_f = Math.round(160*(curHP/maxHP));
    s_ma_f = Math.round(160*(curMA/maxMA));
    s_hp_s = 160 - s_hp_f;
    s_ma_s = 160 - s_ma_f;
    if(document.images['leftp'] && document.images['rightp'] && document.images['leftm'] && document.images['rightm']) 
    {
        document.images['leftp'].width = s_hp_f;
        document.images['rightp'].width = s_hp_s;
        document.images['leftm'].width = s_ma_f;
        document.images['rightm'].width = s_ma_s;
        if(document.getElementById("hbar")) 
        {
            if(curHP<0) curHP = 0;
            var s = document.getElementById("hbar").innerHTML;
            document.getElementById("hbar").innerHTML = window.external.ShowHpMaTimers(s,curHP,maxHP,intHP,curMA,maxMA,intMA);
        }
    }
    curHP = curHP+(maxHP/intHP);
    curMA = curMA+(maxMA/intMA);
}

var Timer = function()
    {
        this.params = {
            show_minutes_above: 60, // (seconds) 0 - don't show minutes
            show_minutes_always: false,
            bg_image: 'http://image.neverlands.ru/map/world/timer.png',
            width: 100,
            height: 100,
            marginTop: -30,

            text_color: '#FFFFFF'
        }
        this.status = 0;
        this.time_left = 0;
        this.timer_interval = false;
        this.parent_object = false;
        this.timer_object = false;
        this.time_object = false;
        this.last_time = 0;

        this.time_start = 0;
        this.time_finish = 0;

        this.onFinish = false;
        this.onTick = false;
        this.onTimeChange = false;
    }

Timer.prototype.attachTo = function(obj)
    {
        this.parent_object = obj;
        return true;
    }

Timer.prototype.tick = function()
    {
        d = new Date();
        curtime = d.getTime();

        pc = Math.ceil(((curtime - this.time_start) / (this.time_end - this.time_start)) * 100)

        if (this.onTick)
            this.onTick(pc);

        if (curtime - this.last_time >= 1000)
        {
            this.last_time = curtime;
            this.timer_func();
        }
    }

Timer.prototype.timer_func = function()
    {
        this.time_left -= 1;
        this.drawTime();

        window.external.SetNeverTimer(this.time_left * 1000);

        if (this.time_left <= 0)
        {
            clearInterval(this.timer_interval);
            if (this.onFinish)
                this.onFinish();
            this.status = 0;
            this.hide();

            location = 'http://www.neverlands.ru/main.php';
        }

        return true;
    }

Timer.prototype.start = function(sec)
    {
        if (sec <= 0)
        {
            if (this.onFinish)
                this.onFinish();

            return true;
        }
        this.time_left = sec;
        this.show();
        this.status = 1;
        var o = this;
        var f = function() { o.tick(); };
        //f = o.timer_func; // seems unused otherwise
        d = new Date();
        this.time_start = d.getTime();
        this.time_end = d.getTime() + (1000*sec);
        this.last_time = d.getTime();
        this.timer_interval = self.setInterval(f, 10);

        return true;
    }

Timer.prototype.show = function()
    {
        if (!this.timer_object)
        {
            if (!this.parent_object)
                this.parent_object = document.body;

            this.timer_object = document.createElement('DIV');
            this.timer_object.style.background = 'url("'+this.params.bg_image+'")';
            this.timer_object.style.position = 'absolute';
            this.timer_object.style.width = this.params.width.toString() + 'px';
            this.timer_object.style.height = this.params.height.toString() + 'px';
            this.timer_object.style.left = '-' + Math.round(this.params.width / 2).toString() +'px'; 
            this.timer_object.style.top = '0px'; 
            this.timer_object.style.marginLeft = '50%';
            this.timer_object.style.marginTop = this.params.marginTop.toString()+'px';


            this.time_object = document.createElement('DIV');
            this.time_object.align = 'center';
            this.time_object.style.paddingTop = '40px';
            this.time_object.style.color = this.params.text_color;

            this.timer_object.appendChild(this.time_object);

            this.parent_object.appendChild(this.timer_object);
        }

        this.timer_object.style.display = 'block';

        this.drawTime();

        return true;
    }

Timer.prototype.hide = function()
    {
        if (this.timer_object)
        {
            this.timer_object.style.display = 'none';
        }

        return true;
    }

Timer.prototype.getFormattedTime = function()
    {
        if (this.params.show_minutes_always || (this.params.show_minutes_above > 0 && this.time_left >= this.params.show_minutes_above))
        {
            min = Math.floor(this.time_left / 60);
            if (min < 10)
                min_str = '0' + min.toString();
            else
                min_str = min.toString();

            sec = this.time_left - min*60;
            if (sec < 10)
                sec_str = '0' + sec.toString();
            else
                sec_str = sec.toString();

            var s = min_str + ':' + sec_str;
        }
        else
            var s = this.time_left.toString();

        return s;
    }

Timer.prototype.drawTime = function(time)
    {
        if (!time)
            time = this.getFormattedTime();
        this.time_object.innerHTML = time;
    }

