function timerst(lp)
{
    time_left_sec -= 1000;

    // +ABC
    window.external.SetNeverTimer(time_left_sec);
    // -ABC

    if(time_left_sec <= 0)
    {
        if(lp)
        {
            ButtonSt(false);
            MapReInit(map[1]);
            finStatus = 0;
        }
        timer_img.src = 'http://image.neverlands.ru/1x1.gif';
        d.getElementById('tdsec').innerHTML = '';
        d.getElementById('timerdiv').style.display = 'none';
        d.getElementById('timerfon').style.display = 'none';
        clearInterval(tsec);

        // +ABC
        if (!d.getElementById("CAPCODE") || (window.external.DoHerbAutoCut() && d.getElementById("CAPCODE").value))
            location = 'http://www.neverlands.ru/main.php';
        // -ABC
    }
    else
    {
        var totalSeconds = time_left_sec / 1000;
        var displayText = totalSeconds;

        if (totalSeconds > 59) {
            var minutes = Math.floor(totalSeconds / 60);
            var seconds = totalSeconds % 60;

            if (minutes < 10) minutes = '0' + minutes;
            if (seconds < 10) seconds = '0' + seconds;

            displayText = minutes + ':' + seconds;
        }

        d.getElementById('tdsec').innerHTML = displayText; 
    }    
}

