                    t += '<div style="margin: 10px auto; background: url('+path+'lf_white.png); width: 384px; height: 53px; text-align: center;"><div style="padding-top: 8px;">'+
                        'Контратака<br />'+
                        '<a style="color:#ff3036; font-size: 11px;" target="_blank" href="http://www.neverlands.ru/logs.fcg?fid='+req['fightid']+'">Идёт бой ('+req['gr1']+' на '+req['gr2']+')</a>'+
                        '<br clear="all" /></div></div>';
                }
            }
        } else {
            t += '<br><i>Нет заявок на контратаку</i><br><br>';
        }

        requestsCount = objStatus['req'].length;
        if (requestsCount > 0) {
            for(i = 0; i < requestsCount; i++) {
                req = objStatus['req'][i];
                if (req['fightid'] == 0) {
                    t += '<div style="margin: 10px auto; background: url('+path+'lf_gray.png); width: 384px; height: 71px; text-align: center;"><div style="padding-top: 8px;">'+
                        'Атака<br>'+
                        'Осталось '+(req['left'] == 1 ? 'меньше 5 минут' : 'больше 5 минут')+'<br />'+
                        (objActions['confirm_'+req['id']] ? ' <input type="button" name="request_confirm" value="Принять бой" onclick="confirmRequest('+req['id']+', \''+objActions['confirm_'+req['id']]+'\')" class="button" />' : '')+
                        (objActions['cancel_'+req['id']]  ? ' <input type="button" name="request_cancel" value="Отменить" onclick="if (confirm(\'Вы уверены, что хотите отменить заявку?\')) cancelRequest('+req['id']+', \''+objActions['cancel_'+req['id']]+'\')" class="button" />' : '')+
                        '<br clear="all" /></div></div>';
                    //timer_add('request_'+req['id'], req['left'], false);
                } else {
                    t += '<div style="margin: 10px auto; background: url('+path+'lf_white.png); width: 384px; height: 53px; text-align: center;"><div style="padding-top: 8px;">'+
                        'Атака от <img src="http://image.neverlands.ru/signs/'+req['sign']+'" /> <b>'+req['signname']+'</b><br>'+
                        '<a style="color:#ff3036; font-size: 11px;" target="_blank" href="http://www.neverlands.ru/logs.fcg?fid='+req['fightid']+'">Идёт бой ('+req['gr1']+' на '+req['gr2']+')</a>'+
                        '<br clear="all" /></div></div>';
                }
            }
        } else {
            t += '<br><i>Нет заявок на атаку</i><br><br>';
        }

        if (objActions['addRequest']) {
            t += '<br /><input type="button" name="request_add" onclick="addRequest(\''+objActions['addRequest']+'\', '+(objStatus['ownerSignId'] === 'bots')+')" value="Атака" class="button" /><br clear="all">';
        }

        if (objActions['addCounterRequest']) {
            t += '<br /><br /><input type="button" name="request_counter_add" onclick="addCounterRequest(\''+objActions['addCounterRequest']+'\')" value="Контратака" class="button" /><br clear="all">';
        }

        t += '<br clear="all"></div>';
        t += '</div>';
        addTimer('siege_finish', objStatus['nextStatusTimeLeft']+5, getStatus, true);
    }

    t += '</div>';
    t += '<div style="background: url(http://image.neverlands.ru/gameplay/outpost/bf_bottom.png) no-repeat; height: 18px;">&nbsp;</div>';
    t += '</div>';

    // Stat
    t += '<div id="attack_stat">';
    if (objStatus['stat'].length > 0)
    {
        t += '<div style="margin: 20px auto 0 auto; width: 748px;">';
        t += '<div style="background: url('+path+'bf_top.png) no-repeat;  height: 20px; text-align: center; ">';
        t += '<div style="background: url('+path+'name2.png) no-repeat; width: 198px; height: 18px; text-align: center; position: absolute; margin-top: -7px; margin-left: 20px; color: #ffffff; font-weight: bold;">';
        t += 'Статистика';
        t += '</div>';
        t += '</div>';
        t += '<div style="background: url('+path+'bf_center_ti.png) repeat-y;">';
        t += '<div style="padding-left: 20px; padding-top: 10px;">';
        for(i = 0; i < objStatus['stat'].length; i++) {
            req = objStatus['stat'][i];
            t += '<img src="http://image.neverlands.ru/signs/'+req['sign']+'" title="'+req['signname']+'">'+req['signname']+'&nbsp;<b style="color: red;">'+req['victories']+' - '+req['defeats']+'</b>';
            t += '<br />';
        }
        t += '</div>';
        t += '</div>';
        t += '<div style="background: url('+path+'bf_bottom.png) no-repeat; height: 18px;">&nbsp;</div>';
        t += '</div>';
    }
    t += '</div>';


    t += '</div>';
    t += '<div style="background: url(http://image.neverlands.ru/gameplay/outpost/bg_down.png) repeat-y; width: 856px; height: 100px; text-align: center;">';
    t += '&nbsp;';
    t += '</div>';

    t += '</div></div>';
    document.getElementById('content').innerHTML = t;
}

function getMainBuidlingContent(response)
{
    if (!objStatus['owner']) {
        return;
    }

    var t = '';
    var i = 0;
    var buildingImages = {'1': 'cook', '2': 'scroll', '3': 'tower', '4': 'weapon'};

    if (objStatus['owner']['buildingType'] == 0 && objStatus['owner']['buildingLevel'] == 0 && objStatus['owner']['buildingStatus'] == 0 && objStatus['owner']['buildingTime'] == 0) {
        t += '<fieldset><legend align="center"><b>Доступные постройки</b></legend><div style="margin: 0 auto; width: 740px;"><br /><table cellpadding=0 cellspacing=0 border=0 style="border-left: 1px solid #e0e0e0; border-top: 1px solid #e0e0e0;"><tr>';
        var building, name;
        if (response && response['buildings']) {
            for (i in response['buildings']) {
                if (response['buildings'].hasOwnProperty(i)) {
                    building = response['buildings'][i];
                    name = response['types'][building['building_type']];
                    t += '<td width="370" align="center" style="border-right: 1px solid #e0e0e0; border-bottom: 1px solid #e0e0e0;" bgcolor=#FCFAF3 valign="top"><font class=weaponch><br><b>' + name + ' (1 ур)</b><br /><img src="http://image.neverlands.ru/gameplay/outpost/shop/' + buildingImages[building['building_type']] + '_1.jpg" width=180 height=91 onmouseover="tooltip(this,\'' + name + '\')" onmouseout="hide_info(this)"><br /><br />' +
                        '<br>Время строительства: ' + showTime(building['upgrade_time']) + '<br /><br />' +
                        '<input type="button" name="startBuilding" value="Начать строительство" class=invbut onclick="startBuilding(' + building['building_type'] + ',objActions[\'build\']);" />' +
                        '</font><br>' +
                        '<br></td>';

                    if (i % 2 == 1) {
                        t += '</tr><tr>';
                    }
                }
            }
        }
        t += '</tr></table></div></fieldset>';
    } else if (objStatus['owner']['buildingType'] != 0 && objStatus['owner']['buildingStatus'] == 1 && objStatus['owner']['buildingTime'] == 0) {
        i = 0;
        if (response && response['resources']) {
            var res;
            t += '<fieldset><legend align="center"><b>Строительство здания</b></legend><div style="text-align: center; margin: 0 auto; width: 740px;"><br />Требуемые ресурсы:<br /><table cellpadding=0 cellspacing=0 border=0 style="border-left: 1px solid #e0e0e0; border-top: 1px solid #e0e0e0;"><tr>';
            for(var r in response['resources']) {
                if (response['resources'].hasOwnProperty(r)) {
                    res = response['resources'][r];
                    res['need'] = parseFloat(res['need']);
                    res['current'] = parseFloat(res['current']);
                    res['massa'] = parseFloat(res['massa']);
                    i++;
                    t += '<td width="125" align="center" style="border-right: 1px solid #e0e0e0; border-bottom: 1px solid #e0e0e0;" bgcolor=#FCFAF3 valign="top"><font class=weaponch><br><img src=http://image.neverlands.ru/resources/' + res['id'] + '.gif width=60 height=60 onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)"><br />' + res['name'] + '<br />' +
                        '<b><font color="' + (res['need'] > res['current'] ? '#a52a2a' : '#00cc00') + '">' + res['current'] + ' / ' + res['need'] + '</font></b>' +
                        '<br>У вас есть: ' + res['massa'] + '<br />' +
                        (res['massa'] > 0 && res['need'] > res['current'] ? '<br /><input type="text" value="0" name="res_' + res['id'] + '" id="res_' + res['id'] + '" size=3 class=weaponch />&nbsp;<input type="button" name="add_res" value="Внести" class=invbut onclick="buildingAddRes(' + res['id'] + ',document.getElementById(\'res_' + res['id'] + '\').value, objActions[\'addResource_'+res['id']+'\']);" />' : '') +
                        '</font><br>';

                    t += '<br></td>';
                    if (i % 8 == 0) {
                        t += '</tr><tr>';
                    }
                }
            }
            t += '</table>';
            if (response['canStart']) {
                t += '<div style="margin: 10px auto; width: 200px;"><input type="button" class="invbut" value="Начать строительство" onclick="startBuildingTimer(objActions[\'startBuildingTimer\'])" style="width: 200px;"></div>';
            }

            t += '</table></div><br /></fieldset>';
        }
    } else if (objStatus['owner']['buildingType'] != 0 && objStatus['owner']['buildingStatus'] == 1 && objStatus['owner']['buildingTime'] > 0) {
        if (response) {
            t += '<fieldset><legend align="center"><b>Строительство здания</b></legend><br /><div style="text-align: center;">';
            if (response['timeLeft'] > 0) {
                t += 'До окончания строительства осталось <b id="timer_building"></b><br />';
                addTimer('building', response['timeLeft'] + 1, function () {
                    document.location = document.location;
                }, true);
                if (response['forceEndPrice'] > 0) {
                    if (response['canForceEnd']) {
                        t += '<br /><input type="button" class="invbut" value="Завершить строительство мгновенно за ' + response['forceEndPrice'] + ' DNV" onclick="if (confirm(\'Вы уверены, что хотите завершить строительство мгновенно за ' + response['forceEndPrice'] + ' DNV?\')) forceEndBuilding(objActions[\'forceEndBuilding\'])" /><br />';
                    } else {
                        t += '<br /><input type="button" class="lbutdis" value="Завершить строительство мгновенно за ' + response['forceEndPrice'] + ' DNV" disabled /><br />';
                    }
                }
            }
            else {
                t += 'Строительство окончено<br />';
                t += '<br /><input type="button" class="invbut" value="Завершить строительство" onclick="finishBuildingTimer(objActions[\'finishBuildingTimer\'])" /><br />';
            }
            t += '<br /></div></fieldset>';
        }
    } else if (objStatus['owner']['buildingType'] != 0 && objStatus['owner']['buildingLevel'] > 0 && objStatus['owner']['buildingStatus'] == 0) {
        if (response) {
            t += '<fieldset><legend align="center"><b>Строительство здания</b></legend><br /><div style="text-align: center;">';
            if (objActions['destroyBuilding']) {
                t += 'Разрушить здание<br />';
                t += '<br /><input type="button" class="invbut" value="Разрушить здание" onclick="if (confirm(\'Вы уверены, что хотите разрушить построенное здание?\')) destroyBuilding(objActions[\'destroyBuilding\'])" /><br />';
            }
            t += '<br /></div></fieldset>';
        }
    }

    return t;
}

function getCraftBuildingContent(response)
{
    var t = '';
    var x, recipe, item, res, weapon, userCount, c;
    var i = 0;
    if (response) {
        if (response['recipes']) {
            t += '<fieldset><legend align="center"><b>Доступные рецепты</b></legend><div style="margin: 0 auto; width: 740px;"><br /><table cellpadding=0 cellspacing=10 border=0 width=100%><tr><td bgcolor=#cccccc><table cellpadding=5 cellspacing=1 border=0 width=100%>';
            t += '<tr> <td bgcolor=#FCFAF3 class=travma align=center><B>Название</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Время</B></td><td bgcolor=#FCFAF3 class=travma align=center><B>Исходные ресурсы</B></td> <td bgcolor=#FCFAF3 class=travma align=center><B>Готовая продукция</B></td><td bgcolor=#FCFAF3 class=travma align=center></td></tr>';
            for(var r in response['recipes']) {
                if (response['recipes'].hasOwnProperty(r)) {
                    recipe = response['recipes'][r];
                    i++;
                    c = (i % 2 == 0 ? '#FFFFFF' : '#FCFAF3');

                    t += '<tr><td bgcolor=' + c + ' class=nickname align=center>' + recipe['name'] + '</td>' +
                    '<td bgcolor=' + c + ' class=travma align=center><b>' + showTime(recipe['craftTime']) + '</b></td>' +
                    '<td bgcolor=' + c + ' align=center>' +
                    '<table><tr>';
                    for(x in recipe['required']) {
                        if (recipe['required'].hasOwnProperty(x)) {
                            t += '<td align="center" class="weaponch">';
                            item = recipe['required'][x];
                            if (item['itemType'] == 1) {
                                if (item['itemId'] == 1) {
                                    t += item['count'] + ' NV';
                                } else if (item['itemId'] == 2) {
                                    t += item['count'] + ' $';
                                } else if (item['itemId'] == 3) {
                                    t += item['count'] + ' DNV';
                                }
                            } else if (item['itemType'] == 2) {
                                res = response['resources'][item['itemId']];
                                t += '<img src="http://image.neverlands.ru/resources/'+item['itemId']+'.gif" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                                userCount = response['playerResources'][item['itemId']] ? response['playerResources'][item['itemId']] : 0;
                                t += userCount + ' / ' + item['count'];
                            } else if (item['itemType'] == 3) {
                                res = response['weapons'][item['itemId']];
                                t += '<img src="http://image.neverlands.ru/weapon/'+res['image']+'" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                                userCount = response['playerWeapons'][item['itemId']] ? response['playerWeapons'][item['itemId']] : 0;
                                t += userCount + ' / ' + item['count'];
                            }
                            t += '</td>';
                        }
                    }
                    t += '</tr></table></td><td bgcolor=' + c + ' align=center><table><tr>';
                    for(x in recipe['result']) {
                        if (recipe['result'].hasOwnProperty(x)) {
                            t += '<td align="center" class="weaponch">';
                            item = recipe['result'][x];
                            if (item['itemType'] == 1) {
                                if (item['itemId'] == 0) {
                                    t += item['count'] + ' NV';
                                } else if (item['itemId'] == 2) {
                                    t += item['count'] + ' $';
                                } else if (item['itemId'] == 3) {
                                    t += item['count'] + ' DNV';
                                }
                            } else if (item['itemType'] == 2) {
                                res = response['resources'][item['itemId']];
                                t += '<img src="http://image.neverlands.ru/resources/'+item['itemId']+'.gif" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                                t += 'x' + item['count'];
                            } else if (item['itemType'] == 3) {
                                res = response['weapons'][item['itemId']];
                                t += '<img src="http://image.neverlands.ru/weapon/'+res['image']+'" onmouseover="tooltip(this,\'' + res['name'] + '\')" onmouseout="hide_info(this)" /><br />';
                                t += 'x' + item['count'];
                            }
                            t += '</td>';
                        }
                    }
                    t += '</tr></table></td><td bgcolor=' + c + ' align=center>';
                    if (recipe['canCraft']) {
                        t += '<input type="button" name="startCraft" onclick="startCraft('+recipe['id']+')" value="Сделать" class=invbut />';
                    } else {
                        t += '<input type="button" value="Сделать" class=lbutdis />';
                    }
                    t += '</td></tr>';
                }
            }
            t += '</table></td></tr></table></div></fieldset>';
        } else {
            t += '<fieldset><legend align="center"><b>Крафт рецепта "'+response['recipeName']+'"</b></legend><div style="margin: 0 auto; width: 740px; text-align: center;"><br />';
            if (response['timeLeft'] > 0) {
                t += 'До окончания крафта осталось <b id="timer_craft"></b><br />';
                addTimer('craft', response['timeLeft'] + 1, function () {
                    getStatus();
                    switchInterface('craft');
                }, true);
                if (objActions['craftCancel']) {
                    t += '<br /><input type="button" class="lbut" value="Отменить крафт" onclick="cancelCraft();" /><br />';
                }
            } else {
                t += 'Крафт завершен<br />';
                if (objActions['craftFinish']) {
                    t += '<br /><input type="button" class="lbut" value="Забрать результат крафта" onclick="finishCraft();" /><br />';
                }
            }
            t += '</div></fieldset>';
        }
    }
    return t;
}

function viewBuilding(building)
{
    if (building == 'main') {
        AjaxGet(scriptName + '?type=outpost&action=getBuilding&building=main&vcode='+objActions['getBuilding']+'&r='+Math.random()+'', function(xdata) {
            var response = JSON.parse(xdata);
            updateData(response);
            updateOutpost(response['r']);
            switchInterface('main');
        });
    } else if (building == 'craft') {
        AjaxGet(scriptName + '?type=outpost&action=getBuilding&building=craft&vcode='+objActions['getBuilding']+'&r='+Math.random()+'', function(xdata) {
            var response = JSON.parse(xdata);
            updateData(response);
            updateOutpost(response['r']);
            switchInterface('craft');
        });
    }
}

function switchInterface(intf)
{
    var outer = document.getElementById('outpost_outer');
    var inner = document.getElementById('outpost_inner');

    if (intf == 'outer') {
        outer.style.display = 'block';
        inner.style.display = 'none';
    } else {
        outer.style.display = 'none';
        inner.style.display = 'block';

        var mb = document.getElementById('main_building');
        var sb = document.getElementById('statue_building');
        var pb = document.getElementById('portal_building');
        var cb = document.getElementById('craft_building');
        mb.style.display = 'none';
        sb.style.display = 'none';
        pb.style.display = 'none';
        cb.style.display = 'none';

        if (intf == 'main') {
            mb.style.display = 'block';
        } else if (intf == 'statue') {
            sb.style.display = 'block';
        } else if (intf == 'portal') {
            pb.style.display = 'block';
        } else if (intf == 'craft') {
            cb.style.display = 'block';
        }
    }
}

function getStatus()
{
    AjaxGet(scriptName + '?type=outpost&action=getStatus&vcode='+objActions['getStatus']+'&r='+Math.random()+'', function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        updateOutpost(response['r']);
    });
}

function startBuilding(building, vcode)
{
