function applyEffect()
{
	window.external.TellBuffTaken();
    var data = {type: 'outpost', action: 'applyEffect', vcode: objActions['applyEffect']};
    AjaxPost(scriptName, data, function (xdata) {
        if (window.external.GetFortBuffsState() === 'TakeBuff') {
            window.external.LeaveFort();
            document.location = 'main.php';
        } else {
            var response = JSON.parse(xdata);
            updateData(response);
            updateOutpost(response['r']);
        }
    });
}

function teleport(place)
{
    var data = {type: 'outpost', action: 'teleport', place: place, vcode: objActions['teleport']};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        if (response['m'].length > 0)
            updateOutpost(response['r']);
        else
            document.location = 'main.php';
    });
}

function addRequest(vcode, start)
{
    var data = {type: 'outpost', action: 'requestAdd', vcode: vcode};
    AjaxPost(scriptName, data, function(xdata) {
        var response = JSON.parse(xdata);
        updateData(response);
        if (!start || response['m'].length > 0) {
            updateOutpost(response['r']);
        } else {
            document.location = 'main.php';
        }
    });
}

