function ajaxParse(data) {
    var arr = data.split('^');

    var butt = arr[0].split('@');
    for (var i = 0; i < butt.length; i++) buttons[i][2] = butt[i];
    DrawButtons();

    var bact = arr[1].split('@');
    for (var i = 0; i < bact.length; i++) {
        items[i] = bact[i];
    }

    var aact = arr[2].split('@');
    for (var i = 1; i < aact.length; i++) {
        actions[i - 1] = aact[i];
    }
    return arr[3];
}

