			td.style.cursor = "pointer";
			td.onclick = function (x, y) { return function () { if (!moved) window.external.mineMoveTo(x, y); }; }(j, i);
            td.style.background = 'url(http://image.neverlands.ru/gameplay/mine_new/' + window.external.getCellImg(j, i) + '.jpg)';
			td.innerHTML = window.external.getMineCellHTML(j, i, pos[2]);

            tr.appendChild(td);
        }
        tbody.appendChild(tr);
    }

    scrollToElement();
}

function move_tunnels(dir) {
    if (disable_move) return false;
    var vcode = '';
    switch (dir) {
        case 'up': vcode = actions[0]; break;
        case 'down': vcode = actions[1]; break;
        case 'left': vcode = actions[2]; break;
        case 'right': vcode = actions[3]; break;
        default: vcode = '';
    }

    AjaxGet('mine_ajax.php?action=move&dir=' + dir + '&pg_id=' + pg_id + '&vcode=' + vcode + '&r=' + Math.random() + '', function (data) {
        data = ajaxParse(data);
        var arr = data.split('@');
        if (arr[0] == 'MOVE') {
            display_move(arr[1], arr[2], arr[3]);
        }
        else {
            MessBoxDiv(arr[1]);
        }
    });
}

var time_left = 0;

function finFunction() {
    show_tunnels();
    EnableButtons();
}

var butt = new Array();
function DrawButtons() {
    butt = new Array();
    btnplace = document.getElementById('ButtonPlace');
    btnplace.innerHTML = '';
    for (var i = 0; i < buttons.length; i++)
        if (buttons[i][2] != '') {
            btnplace.innerHTML += ' <input type=button class=fr_but id="' + buttons[i][0] + '" value="' + buttons[i][1] + '" onclick=\'ButClick("' + buttons[i][0] + '")\'>';
            butt[buttons[i][0]] = [buttons[i][0], buttons[i][1], buttons[i][2]];
        }
}

function DisableButtons() {
    for (var i = 0; i < buttons.length; i++)
        if (buttons[i][2] != '') {
            var b = document.getElementById(buttons[i][0]);
            if (b) b.disabled = true;
        }
    disable_move = true;
}

function EnableButtons() {
    for (var i = 0; i < buttons.length; i++)
        if (buttons[i][2] != '') {
            var b = document.getElementById(buttons[i][0]);
            if (b) b.disabled = false;
        }
    disable_move = false;
}

function ButClick(id) {
    var goloc = '';
    switch (id) {
        case 'inf': goloc = 'main.php?get_id=56&act=10&go=inf&vcode=' + buttons[0][2]; break;
        case 'inv': goloc = 'main.php?get_id=56&act=10&go=inv&vcode=' + buttons[1][2]; break;
        case 'up': goloc = 'main.php?get_id=56&act=10&go=up&vcode=' + buttons[2][2]; break;
        case 'elevdown': ElevatorDown(); break;
        case 'elevup': ElevatorUp(); break;
        case 'digg': Digg(); break;
    }
    if (goloc) {
        location = goloc;
    }
}

function TimerStart(secgo, mrinit) {
    if (time_left_sec <= 0) {
        if (mrinit) {
            ButtonSt(true);
            MapReInit([]);
        }
        time_left_sec = secgo * 1000;
        timer_img.src = 'http://image.neverlands.ru/map/world/timer.png';
        document.getElementById('timerfon').style.display = 'block';
        document.getElementById('timerdiv').style.display = 'block';
        document.getElementById('tdsec').innerHTML = secgo;
        tsec = setInterval('timerst(' + mrinit + ')', 1000);
    }
    else time_left_sec += secgo * 1000;
}

function ElevatorDown() {
    AjaxGet('mine_ajax.php?action=elevdown&pg_id=' + pg_id + '&vcode=' + buttons[4][2] + '&r=' + Math.random() + '', function (data) {
        data = ajaxParse(data);
        var arr = data.split('@');
        if (arr[0] == 'SHOWMINE') {
            display_mine(arr[1], arr[2]);
        }
        else {
            MessBoxDiv(arr[1]);
        }
    });
}

function ElevatorUp() {
    AjaxGet('mine_ajax.php?action=elevup&pg_id=' + pg_id + '&vcode=' + buttons[3][2] + '&r=' + Math.random() + '', function (data) {
        data = ajaxParse(data);
        var arr = data.split('@');
        if (arr[0] == 'SHOWMINE') {
