        }
    });
}

function Digg(vcode) {
    AjaxGet('mine_ajax.php?action=digg&pg_id=' + pg_id + '&vcode=' + buttons[5][2] + '&r=' + Math.random() + '', function (data) {
        data = ajaxParse(data);
        var arr = data.split('@');
        if (arr[0] == 'DIGG') {
            DisableButtons();
            Timer.start(arr[2]);
            Timer.onFinish = function () { EnableButtons(); };
            MessBoxDiv(arr[1]);
        }
        else {
            MessBoxDiv(arr[1]);
        }
    });
}

function StateReady() {
    switch (arr_res[0]) {
        case 'ITEMS':
            ItemsView();
            break;
        case 'ERROR':
            MessBoxDiv(arr_res[1]);
            break;
    }
}

var drag_drop = {
    init: function (container) {
        this.moveState = false;
        this.x0;
        this.y0;
        this.elmX0;
        this.elmY0;
        this.container = container;
        this.scale = 1;

        this.container.onmousedown = function (event) { drag_drop.initMove(event); };
        document.onmouseup = function () { drag_drop.moveState = false; };
        document.onmousemove = function (event) { drag_drop.handlerMove(event); };
        document.onmousewheel = function (e) { drag_drop.handleWheel(event.wheelDelta); };
    },

    mouse_position: function (e) {
        if (!e) { e = window.event; }

        var x = 0;
        var y = 0;

        if (e.pageX) {
            x = e.pageX;
            y = e.pageY;
        }

        if (e.clientX) {
            x = e.clientX + document.documentElement.scrollLeft - document.documentElement.clientLeft;
            y = e.clientY + document.documentElement.scrollTop - document.documentElement.clientTop;
        }

        return { x: x, y: y };
    },

    initMove: function (e) {
        var cord = this.mouse_position(e);
        this.x0 = cord.x;
        this.y0 = cord.y;
        this.elmX0 = parseInt(this.container.style.left);
        this.elmY0 = parseInt(this.container.style.top);
        this.moveState = true;

        e.preventDefault();
    },

    handlerMove: function (e) {
        if (this.moveState) {
            moved = true;
            var cord = this.mouse_position(e);
            this.container.style.left = this.elmX0 + cord.x - this.x0 + "px";
            this.container.style.top = this.elmY0 + cord.y - this.y0 + "px";
        } else {
            moved = false;
        }
    },

    handleWheel: function (delta) {
        if (delta > 0)
            delta = 1;
        else
            delta = -1;

        var newVal = this.scale + delta / 10;
        var spans = this.container.getElementsByTagName("SPAN");
        var nv = parseInt(spans[0].style.fontSize) - delta * 2;

        if (newVal > 1) {
            newVal = 1;
            nv = 10;
        }


        if (newVal < 0.5) {
            newVal = 0.5;
            nv = 20;
        }

        this.scale = newVal;

        document.getElementById("main_tunnels").firstChild.style.transform = "scale(" + this.scale + ")";

        for (var i = 0; i < spans.length; i++) {
            spans[i].style.fontSize = nv + "px";
        }
    }
};

function scrollToElement() {
    var container = document.getElementById("main_tunnels");

    var spans = container.getElementsByTagName("SPAN");
    for (var i = 0; i < spans.length; i++) {
        spans[i].style.fontSize = "10px";
    }
    container.firstChild.style.transform = "scale(1)";

    var newLeft = Math.round(document.documentElement.offsetWidth * 0.49) - cellSize * pos[1] - cellSize / 2;
    container.firstChild.style.left = newLeft + "px";

    var newTop = (document.documentElement.offsetHeight - 85) / 2 - cellSize * pos[0] - cellSize / 2;
    container.firstChild.style.top = newTop + "px";
}
